export function BuildSmartLogo({ filledCount = 13 }: BuildSmartLogoProps) {
  const clamped = Math.min(13, Math.max(0, filledCount));
  const adjustedIndex = clamped === 0 ? 0 : clamped - 1;
  const svgMarkup = frames[adjustedIndex];

  return (
    <div
      className="transition-opacity duration-500"
      style={{ width: 230, height: 245 }}
      dangerouslySetInnerHTML={{ __html: svgMarkup }}
    />
  );
}
